WAVES = ("w1", "w2", "w3", "w4", "w5", "all")


def templates_for_wave(wave: str) -> list[CatalogTemplate]:
    if wave == "all":
        return list(CATALOG_TEMPLATES)
    return [item for item in CATALOG_TEMPLATES if item.wave == wave]
